namespace sv_71f977c35c114436b9a7b313d7727d32.Services;

public enum Theme
{
    Light,
    Dark,
    System
}

/// <summary>
/// Immutable snapshot of theme settings, cascaded app-wide via CascadingValueSource.
/// </summary>
public record ThemeState(Theme Theme, string AccentColor)
{
    public static ThemeState Default => new(Theme.Light, "#0d6efd");
}

using Microsoft.AspNetCore.Components;

namespace sv_71f977c35c114436b9a7b313d7727d32.Services;

/// <summary>
/// Scoped service that owns mutable theme state for a single circuit.
/// Components inject this to read/write theme values.
/// On every change it pushes the new snapshot through CascadingValueSource
/// so all [CascadingParameter] subscribers re-render automatically.
/// </summary>
public class ThemeService
{
    private readonly CascadingValueSource<ThemeState> _source;

    public ThemeService(CascadingValueSource<ThemeState> source)
    {
        _source = source;
    }

    public Theme Theme { get; private set; } = ThemeState.Default.Theme;
    public string AccentColor { get; private set; } = ThemeState.Default.AccentColor;

    /// <summary>
    /// Fired after every state change so components that subscribe via
    /// the service (rather than CascadingParameter) can also react.
    /// </summary>
    public event Action? OnChange;

    public async Task SetThemeAsync(Theme theme)
    {
        Theme = theme;
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string accentColor)
    {
        AccentColor = accentColor;
        await NotifyAsync();
    }

    public async Task SetAllAsync(Theme theme, string accentColor)
    {
        Theme = theme;
        AccentColor = accentColor;
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        var snapshot = new ThemeState(Theme, AccentColor);
        await _source.NotifyChangedAsync(snapshot);
        OnChange?.Invoke();
    }
}

