toolArgs.file_text:
@rendermode InteractiveServer

@inject ThemeService ThemeSvc

<button class="btn btn-sm btn-outline-secondary" @onclick="CycleTheme"
        title="Toggle theme">
    @Icon
</button>

@code {
    [CascadingParameter]
    private ThemeState? ThemeSnapshot { get; set; }

    private string Icon => ThemeSnapshot?.Theme switch
    {
        Theme.Dark   => "🌙",
        Theme.System => "💻",
        _            => "☀️"
    };

    private async Task CycleTheme()
    {
        var next = ThemeSnapshot?.Theme switch
        {
            Theme.Light  => Theme.Dark,
            Theme.Dark   => Theme.System,
            _            => Theme.Light
        };
        await ThemeSvc.SetThemeAsync(next);
    }
}

@page "/settings"
@rendermode InteractiveServer

@inject ThemeService ThemeSvc

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-3" style="max-width: 480px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="btn-group mb-3" role="group">
            @foreach (var t in Enum.GetValues<Theme>())
            {
                <button class="btn @(t == ThemeSnapshot?.Theme ? "btn-primary" : "btn-outline-primary")"
                        @onclick="() => SelectTheme(t)">
                    @t
                </button>
            }
        </div>

        <h5 class="card-title">Accent Color</h5>

        <div class="d-flex align-items-center gap-2 mb-3">
            <input type="color" class="form-control form-control-color"
                   value="@accentColor"
                   @onchange="OnAccentChanged" />
            <span>@accentColor</span>
        </div>

        <div class="alert alert-info mt-3 mb-0">
            Current: <strong>@ThemeSnapshot?.Theme</strong> / <strong>@ThemeSnapshot?.AccentColor</strong>
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeState? ThemeSnapshot { get; set; }

    private string accentColor = ThemeState.Default.AccentColor;

    protected override void OnParametersSet()
    {
        if (ThemeSnapshot is not null)
        {
            accentColor = ThemeSnapshot.AccentColor;
        }
    }

    private async Task SelectTheme(Theme theme)
    {
        await ThemeSvc.SetThemeAsync(theme);
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        accentColor = e.Value?.ToString() ?? accentColor;
        await ThemeSvc.SetAccentColorAsync(accentColor);
    }
}

